import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Validate input length to prevent buffer overflow
        if (userInput.length() > 10) {
            System.out.println("Input exceeds buffer size. Please enter a shorter string.");
            return;
        }

        byte[] buffer = new byte[10]; // Buffer with fixed size 10
        byte[] userInputBytes = userInput.getBytes();

        // Copy input bytes to buffer with bounds checking
        for (int i = 0; i < userInputBytes.length && i < buffer.length; i++) {
            buffer[i] = userInputBytes[i];
        }

        System.out.println("Buffer overflow prevented!");
    }
}

### Explanation:
